;(function(){System.register([],function(exports,module){'use strict';return{execute:function(){(Drupal2=>{const localAnchors={elements:{pageHeader:document.querySelector("[data-header]"),localAnchors:document.querySelectorAll('[href^="#"]'),stickElements:document.querySelectorAll(".odss-sticky")},computed:{stickyElementsHeight:0},methods:{initialize:()=>{localAnchors.events.clickLocalAnchor();localAnchors.events.stickyElementsHeightEvent();},setStickyElementsHeight:()=>{localAnchors.computed.stickyElementsHeight=0;localAnchors.elements.stickElements.forEach(element=>{localAnchors.computed.stickyElementsHeight+=element.offsetHeight;});}},events:{clickLocalAnchor:()=>{[...localAnchors.elements.localAnchors].forEach(localAnchor=>{const target=localAnchor.getAttribute("href")?.replace(/^#/,"");localAnchor.addEventListener("click",event=>{if(target&&document.getElementById(target)){event.preventDefault();let pageHeaderHeight=0;const headerIsVisible=!!localAnchors.elements.pageHeader&&!localAnchors.elements.pageHeader?.classList.contains("js-hidden");if(headerIsVisible&&!localAnchors.elements.stickElements.length){pageHeaderHeight=localAnchors.elements.pageHeader?.offsetHeight;}const targetOffset=document.getElementById(target)?.getBoundingClientRect().top||0;const scrollToYTarget=targetOffset+window.scrollY-pageHeaderHeight-localAnchors.computed.stickyElementsHeight;window.scrollTo({top:scrollToYTarget,behavior:"smooth"});}});});},stickyElementsHeightEvent:()=>{["pageshow","resize"].forEach(event=>window.addEventListener(event,localAnchors.methods.setStickyElementsHeight));}},attach:()=>{localAnchors.methods.initialize();}};Drupal2.behaviors.localAnchors=localAnchors;})(Drupal);}};});})();
